function solveK(M,e){M=((M%(2*Math.PI))+2*Math.PI)%(2*Math.PI);if(M>Math.PI)M-=2*Math.PI;let E=e<0.8?M:Math.PI;for(let i=0;i<30;i++){const d=(E-e*Math.sin(E)-M)/(1-e*Math.cos(E));E-=d;if(Math.abs(d)<1e-10)break;}return E;}
function prop(el,jd){const e=el.e;let n=el.n??GAUSS/Math.pow(el.a,1.5);const M=el.ma+n*(jd-el.epoch);const E=solveK(M,e);const a=el.a;const xo=a*(Math.cos(E)-e);const yo=a*Math.sqrt(1-e*e)*Math.sin(E);const cw=Math.cos(el.w),sw=Math.sin(el.w),co=Math.cos(el.om),so=Math.sin(el.om),ci=Math.cos(el.i),si=Math.sin(el.i);const x1=cw*xo-sw*yo,y1=sw*xo+cw*yo;const y2=ci*y1,z2=si*y1;return [co*x1-so*y2, so*x1+co*y2, z2];}
